        Scanner scanner = new Scanner(System.in);
        String input = scanner.nextLine();
        String[] numbersStr = input.split(" ");
        int[] numbers = new int[numbersStr.length];
        double sum = 0;

        // Convert input numbers to integers and calculate the sum
        for (int i = 0; i < numbersStr.length; i++) {
            numbers[i] = Integer.parseInt(numbersStr[i]);
            sum += numbers[i];
        }

        // Calculate the average
        double avg = sum / numbers.length;

        // Calculate the variance
        double varianceSum = 0;
        for (int i = 0; i < numbers.length; i++) {
            double diff = numbers[i] - avg;
            varianceSum += diff * diff;
        }
        double variance = varianceSum / (numbers.length - 1);

        // Print the results rounded to 2 decimal places
        System.out.printf("%.2f%n", avg);
        System.out.printf("%.2f%n", variance);
    }
}
